declare(strict_types=1);require_once dirname(__DIR__).'/includes/cms.php';$id=cmsId($_GET['id']??0);$q=obtenerConexion()->prepare('SELECT v.*,CONCAT(u.nombre,\' \',u.apellido) administrador FROM website_versiones v JOIN usuarios u ON u.id=v.administrador_id WHERE v.id=:id');$q->execute(['id'=>$id]);$v=$q->fetch();if(!$v){http_response_code(404);exit('Versión no encontrada.');}$antes=json_decode($v['datos_anteriores'],true);$despues=json_decode($v['datos_nuevos'],true);$resumen=function(array$e):array{$r=[];foreach($e as$t=>$filas)$r[$t]=is_array($filas)?count($filas):0;return$r;};cmsCabecera('Comparar versión '.$id,'website/editor.php','Resumen seguro de cambios guardados.');?>
<div class="card card-rounded"><div class="card-body"><p><strong>Administrador:</strong> <?=atenea_e($v['administrador'])?> · <strong>Fecha:</strong> <?=atenea_e($v['created_at'])?> · <strong>Estado:</strong> <?=atenea_e($v['estado'])?></p><div class="row"><div class="col-md-6"><h2 class="h5">Anterior</h2><pre class="bg-light p-3"><?=atenea_e(json_encode($resumen($antes),JSON_PRETTY_PRINT|JSON_UNESCAPED_UNICODE))?></pre></div><div class="col-md-6"><h2 class="h5">Nueva</h2><pre class="bg-light p-3"><?=atenea_e(json_encode($resumen($despues),JSON_PRETTY_PRINT|JSON_UNESCAPED_UNICODE))?></pre></div></div><form method="post" action="accion.php"><input type="hidden" name="csrf_token" value="<?=atenea_e(obtenerTokenCsrf())?>"><input type="hidden" name="version_id" value="<?=$id?>"><button class="btn btn-warning" name="accion" value="restaurar">Restaurar esta versión como borrador</button> <a class="btn btn-light" href="editor.php">Volver</a></form></div></div><?php cmsPie();
